diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9df08553d86e..681525de2a3b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8790,6 +8790,66 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

+  // fcmp (fptrunc X), C -> fcmp X, C' where C' is computed based on the predicate
+  // This avoids the truncation by comparing in the higher precision type.
+  if (match(Op0, m_FPTrunc(m_Value(X)))) {
+    const APFloat *C;
+    if (match(Op1, m_APFloat(C))) {
+      Type *SrcTy = X->getType();
+      const fltSemantics &SrcSem = SrcTy->getScalarType()->getFltSemantics();
+
+      // Skip NaN and infinity constants.
+      if (!C->isNaN() && !C->isInfinity()) {
+        // Convert the constant to the source type to find the boundary.
+        // For oge/ult, we need the midpoint between prev(C) and C.
+        // For ogt/ole, we need the midpoint between C and next(C).
+        bool Lossy;
+
+        switch (Pred) {
+        case FCmpInst::FCMP_OGE:
+        case FCmpInst::FCMP_UGE:
+        case FCmpInst::FCMP_ULT:
+        case FCmpInst::FCMP_OLT: {
+          // For oge/ult: boundary is midpoint between prev(C) and C
+          APFloat PrevC = *C;
+          PrevC.next(true);  // nextDown
+          // Convert both to SrcTy
+          APFloat CSrc = *C;
+          CSrc.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+          APFloat PrevCSrc = PrevC;
+          PrevCSrc.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+          // Compute midpoint: (PrevC + C) / 2 in SrcTy
+          APFloat Midpoint = PrevCSrc;
+          Midpoint.add(CSrc, APFloat::rmNearestTiesToEven);
+          Midpoint.divide(APFloat(SrcSem, 2), APFloat::rmNearestTiesToEven);
+          Constant *NewConst = ConstantFP::get(SrcTy, Midpoint);
+          return new FCmpInst(Pred, X, NewConst, "", &I);
+        }
+        case FCmpInst::FCMP_OGT:
+        case FCmpInst::FCMP_UGT:
+        case FCmpInst::FCMP_OLE:
+        case FCmpInst::FCMP_ULE: {
+          // For ogt/ole: boundary is midpoint between C and next(C)
+          APFloat NextC = *C;
+          NextC.next(false);  // nextUp
+          // Convert both to SrcTy
+          APFloat CSrc = *C;
+          CSrc.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+          APFloat NextCSrc = NextC;
+          NextCSrc.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+          // Compute midpoint: (C + NextC) / 2 in SrcTy
+          APFloat Midpoint = CSrc;
+          Midpoint.add(NextCSrc, APFloat::rmNearestTiesToEven);
+          Midpoint.divide(APFloat(SrcSem, 2), APFloat::rmNearestTiesToEven);
+          Constant *NewConst = ConstantFP::get(SrcTy, Midpoint);
+          return new FCmpInst(Pred, X, NewConst, "", &I);
+        }
+        default:
+          break;
+        }
+      }
+    }
+  }
   // Convert a sign-bit test of an FP value into a cast and integer compare.
   // TODO: Simplify if the copysign constant is 0.0 or NaN.
   // TODO: Handle non-zero compare constants.

