diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9df08553d86e..601867216d15 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8790,6 +8790,103 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

+  // fcmp (fptrunc X), C -> fcmp X, C' where C' is computed based on the predicate
+  // This avoids the truncation by comparing in the higher precision type.
+  if (match(Op0, m_FPTrunc(m_Value(X)))) {
+    const APFloat *C;
+    if (match(Op1, m_APFloat(C))) {
+      Type *SrcTy = X->getType();
+      const fltSemantics &SrcSem = SrcTy->getScalarType()->getFltSemantics();
+      const fltSemantics &DstSem = OpType->getScalarType()->getFltSemantics();
+
+      // Convert the constant to the source type to find the boundary.
+      // For oge/ole, we need the value that rounds to C.
+      // For ogt/olt, we need the value that rounds to nextafter(C).
+      APFloat NewC = *C;
+      bool Lossy;
+
+      switch (Pred) {
+      case FCmpInst::FCMP_OGE:
+      case FCmpInst::FCMP_UGE: {
+        // For >= C, we need the smallest SrcTy value that rounds to >= C.
+        // This is the midpoint between prev(C) and C in SrcTy.
+        APFloat PrevC = *C;
+        PrevC.next(true);  // nextDown
+        APFloat NewC = *C;
+        NewC.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+        APFloat PrevCSrc = PrevC;
+        PrevCSrc.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+        // Compute midpoint: (PrevC + C) / 2 in SrcTy
+        APFloat Midpoint = PrevCSrc;
+        Midpoint.add(NewC, APFloat::rmNearestTiesToEven);
+        Midpoint.divide(APFloat(SrcSem, 2), APFloat::rmNearestTiesToEven);
+        Constant *NewConst = ConstantFP::get(SrcTy, Midpoint);
+        return new FCmpInst(Pred, X, NewConst, "", &I);
+      }
+      case FCmpInst::FCMP_OGT:
+      case FCmpInst::FCMP_UGT: {
+        // For > C, we need the smallest SrcTy value that rounds to > C.
+        // This is the midpoint between C and next(C) in SrcTy.
+        APFloat NextC = *C;
+        NextC.next(false);  // nextUp
+        APFloat NewC = *C;
+        NewC.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+        APFloat NextCSrc = NextC;
+        NextCSrc.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+        // Compute midpoint: (C + NextC) / 2 in SrcTy
+        APFloat Midpoint = NewC;
+        Midpoint.add(NextCSrc, APFloat::rmNearestTiesToEven);
+        Midpoint.divide(APFloat(SrcSem, 2), APFloat::rmNearestTiesToEven);
+        Constant *NewConst = ConstantFP::get(SrcTy, Midpoint);
+        return new FCmpInst(Pred, X, NewConst, "", &I);
+      }
+      case FCmpInst::FCMP_OLE:
+      case FCmpInst::FCMP_ULE: {
+        // For <= C, we need the largest SrcTy value that rounds to <= C.
+        // This is just below the midpoint between C and next(C) in SrcTy.
+        // We use the midpoint between C and next(C) as the boundary for OGE/OGT,
+        // so for OLE we need to use the same logic but with the predicate swapped.
+        APFloat NextC = *C;
+        NextC.next(false);  // nextUp
+        APFloat NewC = *C;
+        NewC.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+        APFloat NextCSrc = NextC;
+        NextCSrc.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+        // Compute midpoint: (C + NextC) / 2 in SrcTy
+        APFloat Midpoint = NewC;
+        Midpoint.add(NextCSrc, APFloat::rmNearestTiesToEven);
+        Midpoint.divide(APFloat(SrcSem, 2), APFloat::rmNearestTiesToEven);
+        // For OLE, we need X < Midpoint, which is equivalent to X <= Midpoint - epsilon
+        // We can use the previous representable value as the boundary
+        Midpoint.next(true);  // nextDown
+        Constant *NewConst = ConstantFP::get(SrcTy, Midpoint);
+        return new FCmpInst(Pred, X, NewConst, "", &I);
+      }
+      case FCmpInst::FCMP_OLT:
+      case FCmpInst::FCMP_ULT: {
+        // For < C, we need the largest SrcTy value that rounds to < C.
+        // This is just below the midpoint between prev(C) and C in SrcTy.
+        APFloat PrevC = *C;
+        PrevC.next(true);  // nextDown
+        APFloat NewC = *C;
+        NewC.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+        APFloat PrevCSrc = PrevC;
+        PrevCSrc.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+        // Compute midpoint: (PrevC + C) / 2 in SrcTy
+        APFloat Midpoint = PrevCSrc;
+        Midpoint.add(NewC, APFloat::rmNearestTiesToEven);
+        Midpoint.divide(APFloat(SrcSem, 2), APFloat::rmNearestTiesToEven);
+        // For OLT, we need X < Midpoint, which is equivalent to X <= Midpoint - epsilon
+        Midpoint.next(true);  // nextDown
+        Constant *NewConst = ConstantFP::get(SrcTy, Midpoint);
+        return new FCmpInst(Pred, X, NewConst, "", &I);
